#include <iostream>
#include <vector>
#include <unordered_map>
#include <sys/socket.h>
#include <netinet/in.h>
#include <unistd.h>
#include <cstring>
#include <thread>
#include <atomic>

struct Player {
    int id;
    float x, y, z;
    float pitch, yaw;
    int health;
    bool alive;
};

struct Packet {
    enum Type { POSITION, SHOOT };
    Type type;
    int player_id;
    float x, y, z;
    float pitch, yaw;
    int target_id;
};

class GameServer {
private:
    int server_fd;
    sockaddr_in address;
    std::unordered_map<int, Player> players;
    std::vector<Packet> packet_queue;
    std::atomic<int> player_counter{0};
    std::atomic<bool> running{false};

public:
    GameServer() {
        server_fd = socket(AF_INET, SOCK_DGRAM, 0);
        address.sin_family = AF_INET;
        address.sin_addr.s_addr = INADDR_ANY;
        address.sin_port = htons(8080);
        bind(server_fd, (struct sockaddr *)&address, sizeof(address));
        running = true;
    }

    void run() {
        std::thread packet_handler(&GameServer::handle_packets, this);
        packet_handler.join();
    }

private:
    void handle_packets() {
        char buffer[1024];
        socklen_t addr_len = sizeof(address);
        
        while (running) {
            int bytes_received = recvfrom(server_fd, buffer, sizeof(buffer), 0,
                                        (struct sockaddr *)&address, &addr_len);
            
            if (bytes_received > 0) {
                Packet packet;
                memcpy(&packet, buffer, sizeof(Packet));
                packet_queue.push_back(packet);
            }
        }
    }

    void process_packets() {
        for (const auto& packet : packet_queue) {
            switch (packet.type) {
                case Packet::POSITION: {
                    auto& player = players[packet.player_id];
                    player.x = packet.x;
                    player.y = packet.y;
                    player.z = packet.z;
                    player.pitch = packet.pitch;
                    player.yaw = packet.yaw;
                    break;
                }
                case Packet::SHOOT: {
                    auto& shooter = players[packet.player_id];
                    auto& target = players[packet.target_id];
                    if (target.alive) {
                        target.health -= 25;
                        if (target.health <= 0) {
                            target.alive = false;
                        }
                    }
                    break;
                }
            }
        }
        packet_queue.clear();
    }
};